variable "repo" {
  description = "GitHub repo in org/name format"
  type        = string
}

variable "environments" {
  description = "Map of environment name to allowed branch/ref pattern and policy ARNs"
  type = map(object({
    ref_pattern = string
    policy_arns = list(string)
  }))
}

variable "oidc_provider_arn" {
  type = string
}

resource "aws_iam_role" "this" {
  for_each = var.environments

  name = "gha-${replace(var.repo, "/", "-")}-${each.key}"
  max_session_duration = 3600

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = {
        Federated = var.oidc_provider_arn
      }
      Action = "sts:AssumeRoleWithWebIdentity"
      Condition = {
        StringEquals = {
          "token.actions.githubusercontent.com:aud" = "sts.amazonaws.com"
        }
        StringLike = {
          "token.actions.githubusercontent.com:sub" = "repo:${var.repo}:${each.value.ref_pattern}"
        }
      }
    }]
  })

  tags = {
    ManagedBy = "terraform"
    Repo      = var.repo
    Env       = each.key
  }
}

resource "aws_iam_role_policy_attachment" "this" {
  for_each = {
    for pair in flatten([
      for env_name, env in var.environments : [
        for policy_arn in env.policy_arns : {
          key        = "${env_name}-${policy_arn}"
          env_name   = env_name
          policy_arn = policy_arn
        }
      ]
    ]) : pair.key => pair
  }

  role       = aws_iam_role.this[each.value.env_name].name
  policy_arn = each.value.policy_arn
}

output "role_arns" {
  value = { for k, v in aws_iam_role.this : k => v.arn }
}

resource "aws_iam_openid_connect_provider" "github" {
  url             = "https://token.actions.githubusercontent.com"
  client_id_list  = ["sts.amazonaws.com"]
  thumbprint_list = var.github_oidc_thumbprints # provider compatibility metadata only
}

resource "aws_iam_policy" "deploy_api" {
  name = "gha-deploy-api"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ecs:UpdateService",
          "ecs:DescribeServices",
          "ecs:RegisterTaskDefinition"
        ]
        Resource = "arn:aws:ecs:us-east-1:${data.aws_caller_identity.current.account_id}:service/prod/api"
      },
      {
        Effect = "Allow"
        Action = ["s3:PutObject", "s3:GetObject"]
        Resource = "arn:aws:s3:::prod-assets/*"
      },
      {
        Effect = "Allow"
        Action = ["iam:PassRole"]
        Resource = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/ecs-task-execution"
        Condition = {
          StringEquals = {
            "iam:PassedToService" = "ecs-tasks.amazonaws.com"
          }
        }
      }
    ]
  })
}

module "api_repo_roles" {
  source = "./modules/github-oidc-role"
  repo   = "acme/api"
  oidc_provider_arn = aws_iam_openid_connect_provider.github.arn
  environments = {
    prod = {
      ref_pattern = "ref:refs/heads/main"
      policy_arns = [aws_iam_policy.deploy_api.arn]
    }
    staging = {
      ref_pattern = "ref:refs/heads/staging"
      policy_arns = [aws_iam_policy.deploy_api_staging.arn]
    }
    pr_readonly = {
      ref_pattern = "pull_request"
      policy_arns = [aws_iam_policy.read_only.arn]
    }
  }
}

import express from 'express';
import http from 'http';

const app = express();
let isShuttingDown = false;
const inFlightRequests = new Set<express.Request>();

app.use((req, res, next) => {
  if (isShuttingDown) {
    res.set('Connection', 'close');
    return res.status(503).send('Server shutting down');
  }
  inFlightRequests.add(req);
  res.on('finish', () => inFlightRequests.delete(req));
  res.on('close', () => inFlightRequests.delete(req));
  next();
});

app.get('/healthz/startup', (_req, res) => {
  if (appReady) res.sendStatus(200);
  else res.sendStatus(503);
});

app.get('/healthz/ready', (_req, res) => {
  if (isShuttingDown) return res.sendStatus(503);
  if (!depsHealthy()) return res.sendStatus(503);
  res.sendStatus(200);
});

app.get('/healthz/live', (_req, res) => {
  res.sendStatus(200);
});

const server = http.createServer(app);
server.keepAliveTimeout = 65_000;
server.headersTimeout = 66_000;
server.listen(3000);

async function shutdown(signal: string) {
  if (isShuttingDown) return;
  console.log(JSON.stringify({ level: 'info', msg: 'shutdown_initiated', signal }));
  isShuttingDown = true;

  server.close(() => {
    console.log(JSON.stringify({ level: 'info', msg: 'http_server_closed' }));
  });

  const deadline = Date.now() + 45_000;
  while (inFlightRequests.size > 0 && Date.now() < deadline) {
    console.log(JSON.stringify({ level: 'info', msg: 'draining', inflight: inFlightRequests.size }));
    await new Promise(r => setTimeout(r, 500));
  }

  if (inFlightRequests.size > 0) {
    console.log(JSON.stringify({ level: 'warn', msg: 'forced_exit_with_inflight', count: inFlightRequests.size }));
  }

  await db.close();
  await redis.quit();
  process.exit(0);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

