import { Pool } from 'pg';
import { setTimeout as sleep } from 'timers/promises';

const BATCH_SIZE = 10_000;
const PAUSE_MS = 1000;
const MAX_REPLICATION_LAG_BYTES = 100 * 1024 * 1024;

async function getReplicationLag(pool: Pool): Promise<number> {
  const { rows } = await pool.query(`
    SELECT COALESCE(MAX(pg_wal_lsn_diff(pg_current_wal_lsn(), replay_lsn)), 0) AS lag_bytes
    FROM pg_stat_replication
  `);
  return Number(rows[0].lag_bytes);
}

async function main() {
  const pool = new Pool({ connectionString: process.env.DATABASE_URL, max: 2 });
  let totalUpdated = 0;
  const startedAt = Date.now();

  while (true) {
    const lag = await getReplicationLag(pool);
    if (lag > MAX_REPLICATION_LAG_BYTES) {
      console.log(JSON.stringify({ event: 'pausing_for_lag', lag_bytes: lag }));
      await sleep(10_000);
      continue;
    }

    const result = await pool.query(`
      WITH batch AS (
        SELECT id FROM users
        WHERE email IS NULL
        ORDER BY id
        LIMIT $1
        FOR UPDATE SKIP LOCKED
      )
      UPDATE users u
      SET email = u.email_address
      FROM batch b
      WHERE u.id = b.id
      RETURNING u.id
    `, [BATCH_SIZE]);

    totalUpdated += result.rowCount ?? 0;
    console.log(JSON.stringify({
      event: 'batch_complete',
      updated_in_batch: result.rowCount,
      total_updated: totalUpdated,
      replication_lag_bytes: lag,
      elapsed_seconds: (Date.now() - startedAt) / 1000,
    }));

    if ((result.rowCount ?? 0) < BATCH_SIZE) {
      console.log(JSON.stringify({ event: 'backfill_complete', total: totalUpdated }));
      break;
    }

    await sleep(PAUSE_MS);
  }

  const { rows } = await pool.query('SELECT count(*) FROM users WHERE email IS NULL');
  if (rows[0].count !== '0') {
    throw new Error(`Backfill incomplete: ${rows[0].count} rows still NULL`);
  }
  await pool.end();
}

main().catch(err => { console.error(err); process.exit(1); });

-- Stage 5: CONTRACT. Only run after 7+ days of stage 4 (code uses email exclusively).
-- Pre-flight check enforced by deploy script:
--   SELECT count(*) FROM users WHERE email IS NULL = 0
--   AND no app code references email_address in production for 7 days (Datadog log search)

BEGIN;

DROP TRIGGER IF EXISTS users_sync_email ON users;
DROP FUNCTION IF EXISTS sync_email_columns();

-- Make email NOT NULL since all rows are now populated and code writes to it
ALTER TABLE users ALTER COLUMN email SET NOT NULL;

-- Drop the old column. THIS IS IRREVERSIBLE without restore from snapshot.
ALTER TABLE users DROP COLUMN email_address;

COMMIT;

