import { SecretsManagerClient, GetSecretValueCommand } from '@aws-sdk/client-secrets-manager';

const client = new SecretsManagerClient({});
const CACHE_TTL_MS = 5 * 60 * 1000;
const REFRESH_BEFORE_EXPIRY_MS = 60 * 1000;

interface CachedSecret { value: any; fetchedAt: number; refreshing: boolean; }
const cache = new Map<string, CachedSecret>();

export async function getSecret<T = Record<string, any>>(secretId: string): Promise<T> {
  const now = Date.now();
  const cached = cache.get(secretId);

  if (cached && now - cached.fetchedAt < CACHE_TTL_MS) {
    if (now - cached.fetchedAt > CACHE_TTL_MS - REFRESH_BEFORE_EXPIRY_MS && !cached.refreshing) {
      cached.refreshing = true;
      refresh(secretId).finally(() => { cached.refreshing = false; });
    }
    return cached.value;
  }

  return refresh<T>(secretId);
}

async function refresh<T = any>(secretId: string): Promise<T> {
  try {
    const res = await client.send(new GetSecretValueCommand({ SecretId: secretId }));
    if (!res.SecretString) throw new Error(`Secret ${secretId} has no SecretString`);
    const value = JSON.parse(res.SecretString);
    cache.set(secretId, { value, fetchedAt: Date.now(), refreshing: false });
    return value;
  } catch (err) {
    const stale = cache.get(secretId);
    if (stale) {
      console.warn(JSON.stringify({
        level: 'warn',
        msg: 'secret_refresh_failed_using_stale',
        secretId,
        stale_age_ms: Date.now() - stale.fetchedAt,
        err: (err as Error).message,
      }));
      return stale.value;
    }
    throw err;
  }
}

export function clearCache() { cache.clear(); }

import { Pool } from 'pg';
import { getSecret } from './config/secrets';

interface DbCredentials {
  username: string;
  password: string;
  host: string;
  port: number;
  dbname: string;
}

let pool: Pool | null = null;
let currentPassword: string | null = null;

export async function getPool(): Promise<Pool> {
  const creds = await getSecret<DbCredentials>('prod/api/db-credentials');

  if (pool && currentPassword === creds.password) {
    return pool;
  }

  if (pool && currentPassword !== creds.password) {
    console.log(JSON.stringify({ level: 'info', msg: 'db_credentials_rotated_reconnecting' }));
    const old = pool;
    setTimeout(() => old.end().catch(() => {}), 30_000);
  }

  pool = new Pool({
    user: creds.username,
    password: creds.password,
    host: creds.host,
    port: creds.port,
    database: creds.dbname,
    max: 20,
    idleTimeoutMillis: 30_000,
    connectionTimeoutMillis: 5_000,
  });
  currentPassword = creds.password;
  return pool;
}

