resource "aws_athena_named_query" "secrets_access_daily" {
  name      = "secrets-access-daily"
  database  = aws_athena_database.cloudtrail.name
  query     = <<-SQL
    SELECT
      from_iso8601_timestamp(eventtime) AS ts,
      requestparameters AS req,
      useridentity.arn AS caller,
      json_extract_scalar(json_parse(requestparameters), '$.secretId') AS secret_id,
      errorcode,
      sourceipaddress
    FROM cloudtrail_logs
    WHERE eventsource = 'secretsmanager.amazonaws.com'
      AND eventname = 'GetSecretValue'
      AND eventtime BETWEEN date_format(current_date - interval '1' day, '%Y-%m-%dT00:00:00Z')
                       AND date_format(current_date, '%Y-%m-%dT00:00:00Z')
    ORDER BY ts DESC
  SQL
}

