resource "aws_sfn_state_machine" "dr_failover" {
  name     = "dr-failover"
  role_arn = aws_iam_role.dr_failover_sfn.arn
  definition = jsonencode({
    Comment = "Promote DR region to active"
    StartAt = "VerifyPrimaryDown"
    States = {
      VerifyPrimaryDown = {
        Type = "Task"
        Resource = aws_lambda_function.verify_primary_health.arn
        Next = "PromoteReplica"
        Retry = [{ ErrorEquals = ["PrimaryStillHealthy"], MaxAttempts = 0 }]
        Catch = [{ ErrorEquals = ["PrimaryStillHealthy"], Next = "AbortPrimaryHealthy" }]
      }
      AbortPrimaryHealthy = {
        Type = "Fail"
        Cause = "Primary region is healthy - aborting failover"
      }
      PromoteReplica = {
        Type = "Task"
        Resource = "arn:aws:states:::aws-sdk:rds:promoteReadReplica"
        Parameters = {
          DbInstanceIdentifier = "prod-pg-dr-replica"
          BackupRetentionPeriod = 7
        }
        Next = "WaitForPromotion"
      }
      WaitForPromotion = {
        Type = "Wait"
        Seconds = 60
        Next = "UpdateSecretsManager"
      }
      UpdateSecretsManager = {
        Type = "Task"
        Resource = aws_lambda_function.update_db_secret.arn
        Parameters = { Region = "us-west-2" }
        Next = "ScaleECS"
      }
      ScaleECS = {
        Type = "Parallel"
        Branches = [
          { StartAt = "ScaleApi", States = { ScaleApi = { Type = "Task", Resource = "arn:aws:states:::aws-sdk:ecs:updateService", Parameters = { Cluster = "prod-dr", Service = "api", DesiredCount = 8 }, End = true }}},
          { StartAt = "ScaleWorker", States = { ScaleWorker = { Type = "Task", Resource = "arn:aws:states:::aws-sdk:ecs:updateService", Parameters = { Cluster = "prod-dr", Service = "worker", DesiredCount = 4 }, End = true }}}
        ]
        Next = "WaitForHealthy"
      }
      WaitForHealthy = {
        Type = "Task"
        Resource = aws_lambda_function.wait_for_targets_healthy.arn
        Parameters = { Region = "us-west-2", TimeoutSeconds = 300 }
        Next = "NotifySlack"
        Catch = [{ ErrorEquals = ["States.Timeout"], Next = "NotifyTimeout" }]
      }
      NotifyTimeout = { Type = "Fail", Cause = "Targets did not become healthy in 5 min" }
      NotifySlack = {
        Type = "Task"
        Resource = aws_lambda_function.slack_notify.arn
        Parameters = { Message = "DR failover complete. Secondary now active. Route 53 should follow within 30s." }
        End = true
      }
    }
  })
}

