import { Worker } from 'bullmq';
import { register, Gauge } from 'prom-client';
import CircuitBreaker from 'opossum';

const jobsWaiting = new Gauge({ name: 'bullmq_jobs_waiting', help: 'Jobs waiting in queue', labelNames: ['queue'] });
const jobsActive = new Gauge({ name: 'bullmq_jobs_active', help: 'Jobs currently processing', labelNames: ['queue'] });
const jobsFailed = new Gauge({ name: 'bullmq_jobs_failed', help: 'Failed jobs count', labelNames: ['queue'] });

const breaker = new CircuitBreaker(async (job: any) => {
  return await callDownstream(job.data);
}, {
  timeout: 10_000,
  errorThresholdPercentage: 50,
  resetTimeout: 30_000,
  volumeThreshold: 20,
});

breaker.on('open', () => console.log(JSON.stringify({ level: 'warn', msg: 'circuit_open' })));
breaker.on('halfOpen', () => console.log(JSON.stringify({ level: 'info', msg: 'circuit_halfopen' })));

const worker = new Worker('default', async (job) => {
  if (breaker.opened) {
    throw new Error('downstream_circuit_open');
  }
  return await breaker.fire(job);
}, {
  connection: { host: 'redis-prod.acme.internal', port: 6379, password: process.env.REDIS_PASSWORD },
  concurrency: 8,
});

setInterval(async () => {
  const counts = await worker.queue?.getJobCounts('wait', 'active', 'failed');
  if (counts) {
    jobsWaiting.set({ queue: 'default' }, counts.wait || 0);
    jobsActive.set({ queue: 'default' }, counts.active || 0);
    jobsFailed.set({ queue: 'default' }, counts.failed || 0);
  }
}, 5000);

