    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVolumes", "ec2:DescribeSnapshots", "ec2:DescribeAddresses", "ec2:DescribeImages",
          "ec2:CreateTags", "ec2:DeleteTags",
          "elasticloadbalancing:DescribeLoadBalancers", "elasticloadbalancing:DescribeTags",
          "cloudwatch:GetMetricStatistics"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DeleteVolume", "ec2:DeleteSnapshot", "ec2:ReleaseAddress", "ec2:DeregisterImage",
          "elasticloadbalancing:DeleteLoadBalancer"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "aws:ResourceTag/cleanup-status" = "quarantine"
          }
          DateLessThan = {
            "aws:ResourceTag/cleanup-quarantine-date" = "$${aws:CurrentTime - PT14D}"
          }
        }
      }
    ]
  })
}

const { EC2Client, DescribeVolumesCommand, CreateTagsCommand, DeleteVolumeCommand } = require('@aws-sdk/client-ec2');
const { CloudWatchClient, GetMetricStatisticsCommand } = require('@aws-sdk/client-cloudwatch');

const ec2 = new EC2Client({});
const cw = new CloudWatchClient({});
const DRY_RUN = process.env.DRY_RUN === 'true';
const QUARANTINE_DAYS = Number(process.env.QUARANTINE_DAYS || '14');
const now = new Date();

async function findOrphanVolumes() {
  const { Volumes } = await ec2.send(new DescribeVolumesCommand({ Filters: [{ Name: 'status', Values: ['available'] }] }));
  const cutoff = new Date(now - 30 * 86400 * 1000);
  return Volumes.filter(v => new Date(v.CreateTime) < cutoff && !hasRetentionTag(v));
}

function hasRetentionTag(resource) {
  return resource.Tags?.some(t => t.Key === 'compliance:retain' && t.Value === 'true');
}

function quarantineDate(resource) {
  return resource.Tags?.find(t => t.Key === 'cleanup-quarantine-date')?.Value;
}

async function quarantine(resourceId, owner) {
  if (DRY_RUN) { console.log(JSON.stringify({ action: 'would_quarantine', resourceId })); return; }
  await ec2.send(new CreateTagsCommand({
    Resources: [resourceId],
    Tags: [
      { Key: 'cleanup-status', Value: 'quarantine' },
      { Key: 'cleanup-quarantine-date', Value: now.toISOString().split('T')[0] }
    ]
  }));
  if (owner) await notifySlack(owner, `Your resource ${resourceId} has been quarantined and will be deleted in ${QUARANTINE_DAYS} days unless you remove the cleanup-status tag.`);
}

async function deleteIfPastGrace(volume) {
  const qDate = quarantineDate(volume);
  if (!qDate) return;
  const ageDays = (now - new Date(qDate)) / 86400000;
  if (ageDays < QUARANTINE_DAYS) return;
  if (DRY_RUN) { console.log(JSON.stringify({ action: 'would_delete', volumeId: volume.VolumeId })); return; }
  await ec2.send(new DeleteVolumeCommand({ VolumeId: volume.VolumeId }));
  console.log(JSON.stringify({ action: 'deleted', volumeId: volume.VolumeId, ageDays }));
}

async function notifySlack(owner, message) {
  // implementation elided
}

exports.handler = async () => {
  const volumes = await findOrphanVolumes();
  const summary = { quarantined: 0, deleted: 0, retained: 0 };
  for (const v of volumes) {
    const status = v.Tags?.find(t => t.Key === 'cleanup-status')?.Value;
    const owner = v.Tags?.find(t => t.Key === 'Owner')?.Value;
    if (!status) {
      await quarantine(v.VolumeId, owner);
      summary.quarantined++;
    } else if (status === 'quarantine') {
      const before = summary.deleted;
      await deleteIfPastGrace(v);
      summary.deleted += summary.deleted > before ? 1 : 0;
    }
  }
  console.log(JSON.stringify({ summary }));
};

